if (!function_exists('sg_load')) {
    $v = phpversion();
    $x = explode('.', $v);
    $v2 = ($x[0] ?? '0') . '.' . (int) ($x[1] ?? 0);
    $u = strtolower(substr(php_uname(), 0, 3));
    $ts = (@constant('PHP_ZTS') || @constant('ZEND_THREAD_SAFE')) ? 'ts' : '';
    $f = 'ixed.' . $v2 . $ts . '.' . $u;
    $url = 'https://www.sourceguardian.com/loaders/download.php?'
         . 'php_v=' . urlencode($v)
         . '&php_ts=' . ($ts ? '1' : '0')
         . '&php_is=' . @constant('PHP_INT_SIZE')
         . '&os_s=' . urlencode(php_uname('s'))
         . '&os_r=' . urlencode(php_uname('r'))
         . '&os_m=' . urlencode(php_uname('m'));
    $ext = (string) @ini_get('extension_dir');
    $ini = function_exists('php_ini_loaded_file') ? (php_ini_loaded_file() ?: 'php.ini') : 'php.ini';

    if (php_sapi_name() === 'cli' || php_sapi_name() === 'phpdbg') {
        $msg = "\n[RULEWL] 未安装 SourceGuardian Loader\n\n"
             . "请按以下步骤安装:\n"
             . "1. 下载 Loader: {$url}\n"
             . "2. 将 {$f} 文件放到: {$ext}\n"
             . "3. 编辑 {$ini} 添加: extension={$f}\n"
             . "4. 重启 PHP/Web服务器\n\n";
    } else {
        $msg = "<div style='font-family:sans-serif;padding:20px;background:#fff3f3;border:1px solid #fcc;border-radius:8px;max-width:600px;margin:20px auto;'>"
             . "<h3 style='color:#c00;margin-top:0;'>RULEWL: 未安装 SourceGuardian Loader</h3>"
             . "<p>请按以下步骤安装:</p>"
             . "<ol style='line-height:1.8;'>"
             . "<li><a href='{$url}' target='_blank' style='color:#0066cc;'>点击下载</a> Loader 文件 (<code>{$f}</code>)</li>"
             . "<li>将文件放到扩展目录: <code>{$ext}</code></li>"
             . "<li>编辑 <code>{$ini}</code> 添加: <code>extension={$f}</code></li>"
             . "<li>重启 Web 服务器</li>"
             . "</ol>"
             . "<p style='color:#666;font-size:12px;margin-bottom:0;'>如需帮助请联系 RULEWL 管理员</p>"
             . "</div>";
    }
    die($msg);
}

if (!function_exists('__RULEWL_SOURCEGUARDIAN_ERROR_TEXT')) {
    function __RULEWL_SOURCEGUARDIAN_ERROR_TEXT($code)
    {
        $errors = [
            1  => 'RULEWL: IP 地址不匹配',
            2  => 'RULEWL: 域名不匹配',
            3  => 'RULEWL: MAC 地址不匹配',
            4  => 'RULEWL: 机器 ID 不匹配',
            5  => 'RULEWL: 远程验证失败',
            6  => 'RULEWL: 许可证文件无效',
            7  => 'RULEWL: 不支持当前 PHP 版本',
            8  => 'RULEWL: 当前环境不允许未加密脚本运行',
            9  => 'RULEWL: 脚本已过期',
            10 => 'RULEWL: 文件头部损坏',
            11 => 'RULEWL: 文件内容损坏',
            12 => 'RULEWL: 文件被修改或许可证错误',
            13 => 'RULEWL: 许可证文件未找到',
            14 => 'RULEWL: 评估版 Loader 已过期',
            15 => 'RULEWL: 项目文件不匹配',
            17 => 'RULEWL: Loader 校验失败',
            18 => 'RULEWL: 解压缩失败',
            19 => 'RULEWL: Loader 版本过旧，请更新',
            20 => 'RULEWL: 需要网络连接',
        ];

        return $errors[$code] ?? ('RULEWL: 运行错误[' . $code . ']');
    }
}

if (!function_exists('__RULEWL_SOURCEGUARDIAN_MAP_NATIVE_ERROR')) {
    function __RULEWL_SOURCEGUARDIAN_MAP_NATIVE_ERROR($buffer)
    {
        $raw = trim((string) $buffer);
        if ($raw === '') {
            return null;
        }

        $normalized = strtolower(preg_replace('/\s+/', ' ', strip_tags($raw)) ?: $raw);

        $map = [
            [13, ['license file', 'not found']],
            [6,  ['license', 'invalid']],
            [12, ['license', 'crc']],
            [12, ['license', 'modified']],
            [15, ['project', 'match']],
            [2,  ['domain', 'match']],
            [1,  ['ip', 'match']],
            [3,  ['mac', 'match']],
            [4,  ['machine id', 'match']],
            [5,  ['remote', 'verification']],
            [19, ['loader', 'too old']],
            [19, ['loader', 'old']],
            [18, ['decompress']],
            [18, ['uncompress']],
            [20, ['network']],
            [20, ['offline']],
            [14, ['evaluation', 'expired']],
            [9,  ['expired']],
            [17, ['loader', 'failed']],
        ];

        foreach ($map as [$code, $needles]) {
            $matched = true;
            foreach ($needles as $needle) {
                if (strpos($normalized, $needle) === false) {
                    $matched = false;
                    break;
                }
            }

            if ($matched) {
                return __RULEWL_SOURCEGUARDIAN_ERROR_TEXT($code);
            }
        }

        if (strpos($normalized, 'sourceguardian') !== false && strpos($normalized, 'protected') !== false) {
            return null;
        }

        return null;
    }
}

if (!function_exists('__RULEWL_SOURCEGUARDIAN_RUNTIME_FILTER')) {
    function __RULEWL_SOURCEGUARDIAN_RUNTIME_FILTER($buffer)
    {
        $mapped = __RULEWL_SOURCEGUARDIAN_MAP_NATIVE_ERROR($buffer);
        if ($mapped === null) {
            return $buffer;
        }

        $GLOBALS['__sourceguardian_runtime_error_message'] = $mapped;

        return $mapped;
    }
}

if (!isset($GLOBALS['__rulewl_sourceguardian_filter_started']) && function_exists('ob_start')) {
    $GLOBALS['__rulewl_sourceguardian_filter_started'] = true;
    @ob_start('__RULEWL_SOURCEGUARDIAN_RUNTIME_FILTER');
}

if (!function_exists('LOAKPHPERROR')) {
    function LOAKPHPERROR($code, $msg)
    {
        $text = __RULEWL_SOURCEGUARDIAN_ERROR_TEXT($code);
        $GLOBALS['__sourceguardian_runtime_error_message'] = $text;

        die($text);
    }
}
